+os.close(fd)
+
+# List /tmp — verifies fd_readdir handles FD_TMP_PREOPEN
+entries = os.listdir('/tmp')
+basename = os.path.basename(path)
+print(basename in entries)
+
+# Read it back
+with open(path) as f:
+    print(f.read())
+
+# Cleanup
+os.unlink(path)
+print('OK')
+    `);
